public sealed class EventSafetyService
{
    private static readonly HashSet<string> Decisions=["deny","remove"],Reasons=["safeguarding_policy","minimum_age","guardian_consent","code_of_conduct","conduct_violation","safety_review","user_block"],Relationships=["parent","guardian","legal_guardian","carer"];
    private readonly NexusDbContext _db;private readonly IDataProtector _protector;private readonly IEmailService _mail;private readonly IConfiguration _config;
    public EventSafetyService(NexusDbContext db,IDataProtectionProvider protection,IEmailService mail,IConfiguration config){_db=db;_protector=protection.CreateProtector("Nexus.EventSafety.Guardian.v1");_mail=mail;_config=config;}

    public async Task<EventSafetyResult> ReadAsync(int tenant,int eventId,int actor,CancellationToken ct){var c=await Context(tenant,eventId,actor,false,ct);if(!c.Ok)return c.Error!;return new(await Project(tenant,c.Event!,c.Actor!,c.Manage,ct));}
    public async Task<EventSafetyResult> SaveDraftAsync(int tenant,int eventId,int actor,JsonElement body,string key,CancellationToken ct)
    {
        if(!ValidKey(key))return Validation("idempotency_key");var parsed=ParseDraft(body);if(parsed is null)return Validation("requirements");var expected=LongN(body,"expected_revision");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,true,ct);if(!c.Ok)return c.Error!;var requestHash=Hash(body.GetRawText());var kh=Hash(key);var replay=await _db.EventSafetyRequirementHistory.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.IdempotencyHash==kh,ct);if(replay is not null){if(replay.EventId!=eventId||replay.Action!="saved"||replay.RequestHash!=requestHash)return Conflict();await tx.CommitAsync(ct);return new(await Project(tenant,c.Event!,c.Actor!,true,ct));}
        var head=await _db.EventSafetyRequirements.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId,ct);if(head is null){if(expected is not null and not 0)return Conflict();head=new(){TenantId=tenant,EventId=eventId,CreatedByUserId=actor,UpdatedByUserId=actor};_db.Add(head);await _db.SaveChangesAsync(ct);}else{if(head.Status=="archived"||expected!=head.Revision)return Conflict();head.Revision++;head.CurrentVersion++;head.Status="draft";head.PublishedVersion=null;head.PublishedAt=null;head.PublishedByUserId=null;head.UpdatedByUserId=actor;head.UpdatedAt=DateTime.UtcNow;}
        var version=new EventSafetyRequirementVersion{TenantId=tenant,EventId=eventId,RequirementsId=head.Id,VersionNumber=head.CurrentVersion,MinimumAge=parsed.MinimumAge,GuardianConsentRequired=parsed.Guardian,MinorAgeThreshold=parsed.Guardian?parsed.Threshold:null,CodeOfConductRequired=parsed.CodeRequired,CodeOfConductText=parsed.CodeRequired?parsed.CodeText:null,CodeOfConductTextVersion=parsed.CodeRequired?parsed.CodeVersion:null,CodeOfConductTextHash=parsed.CodeRequired?Hash(parsed.CodeText!):null,EligibilityPolicyHash=Hash(JsonSerializer.Serialize(parsed)),CapturedByUserId=actor,IdempotencyHash=kh,RequestHash=requestHash};_db.Add(version);await _db.SaveChangesAsync(ct);_db.Add(new EventSafetyRequirementHistory{TenantId=tenant,EventId=eventId,RequirementsId=head.Id,RequirementsRevision=head.Revision,RequirementsVersionId=version.Id,RequirementsVersionNumber=version.VersionNumber,Action="saved",ActorUserId=actor,IdempotencyHash=kh,RequestHash=requestHash});await _db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return new(await Project(tenant,c.Event!,c.Actor!,true,ct));
    }
    public Task<EventSafetyResult> PublishAsync(int t,int e,int a,long revision,int version,string key,CancellationToken ct)=>Transition(t,e,a,revision,version,key,false,ct);
    public Task<EventSafetyResult> ArchiveAsync(int t,int e,int a,long revision,int version,string key,CancellationToken ct)=>Transition(t,e,a,revision,version,key,true,ct);
    private async Task<EventSafetyResult> Transition(int tenant,int eventId,int actor,long revision,int version,string key,bool archive,CancellationToken ct){if(!ValidKey(key)||revision<1||version<1)return Validation("requirements_version");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,true,ct);if(!c.Ok)return c.Error!;var action=archive?"archived":"published";var kh=Hash(key);var replay=await _db.EventSafetyRequirementHistory.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.IdempotencyHash==kh,ct);if(replay is not null){if(replay.EventId!=eventId||replay.Action!=action)return Conflict();await tx.CommitAsync(ct);return new(await Project(tenant,c.Event!,c.Actor!,true,ct));}var head=await _db.EventSafetyRequirements.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId,ct);if(head is null)return Missing();if(head.Revision!=revision||head.CurrentVersion!=version||head.Status=="archived"||!archive&&head.Status!="draft")return Conflict();var snapshot=await _db.EventSafetyRequirementVersions.IgnoreQueryFilters().SingleAsync(x=>x.TenantId==tenant&&x.RequirementsId==head.Id&&x.VersionNumber==version,ct);head.Revision++;head.Status=action;head.UpdatedByUserId=actor;head.UpdatedAt=DateTime.UtcNow;if(archive){head.ArchivedByUserId=actor;head.ArchivedAt=DateTime.UtcNow;}else{head.PublishedVersion=version;head.PublishedByUserId=actor;head.PublishedAt=DateTime.UtcNow;}_db.Add(new EventSafetyRequirementHistory{TenantId=tenant,EventId=eventId,RequirementsId=head.Id,RequirementsRevision=head.Revision,RequirementsVersionId=snapshot.Id,RequirementsVersionNumber=version,Action=action,ActorUserId=actor,IdempotencyHash=kh,RequestHash=Hash(new{revision,version,action})});await _db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return new(await Project(tenant,c.Event!,c.Actor!,true,ct));}

    public async Task<EventSafetyResult> AcknowledgeAsync(int tenant,int eventId,int actor,string textVersion,string textHash,string key,CancellationToken ct){if(!ValidKey(key)||!Regex.IsMatch(textHash??"","^[0-9a-f]{64}$"))return Validation("text_version");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,false,ct);if(!c.Ok)return c.Error!;var p=await Published(tenant,eventId,ct);if(p is null||!p.Value.Version.CodeOfConductRequired||p.Value.Version.CodeOfConductTextVersion!=textVersion||p.Value.Version.CodeOfConductTextHash!=textHash)return Conflict();var kh=Hash(key);var replay=await _db.EventSafetyCodeAcknowledgements.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.IdempotencyHash==kh,ct);if(!replay){var prior=await CurrentAck(tenant,eventId,actor,ct);var seq=(await _db.EventSafetyCodeAcknowledgements.IgnoreQueryFilters().Where(x=>x.TenantId==tenant&&x.EventId==eventId&&x.UserId==actor).MaxAsync(x=>(long?)x.EvidenceSequence,ct)??0)+1;if(prior is not null)_db.Add(AckEvidence(prior,"replaced",seq++,kh+"-replace",Hash("replace:"+key),actor));_db.Add(new EventSafetyCodeAcknowledgement{TenantId=tenant,EventId=eventId,RequirementsId=p.Value.Head.Id,RequirementsVersionId=p.Value.Version.Id,RequirementsVersionNumber=p.Value.Version.VersionNumber,UserId=actor,EvidenceSequence=seq,Action="acknowledged",TextVersion=textVersion,TextHash=textHash,AcknowledgedAt=DateTime.UtcNow,ActorUserId=actor,IdempotencyHash=kh,RequestHash=Hash(new{textVersion,textHash})});await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);return new(await Project(tenant,c.Event!,c.Actor!,c.Manage,ct));}
    public async Task<EventSafetyResult> WithdrawAckAsync(int tenant,int eventId,int actor,long id,string key,CancellationToken ct){if(!ValidKey(key))return Validation("idempotency_key");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,false,ct);if(!c.Ok)return c.Error!;var ack=await _db.EventSafetyCodeAcknowledgements.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.UserId==actor&&x.Id==id&&x.Action=="acknowledged",ct);if(ack is null)return Missing();var kh=Hash(key);if(!await _db.EventSafetyCodeAcknowledgements.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.IdempotencyHash==kh,ct)){var seq=(await _db.EventSafetyCodeAcknowledgements.IgnoreQueryFilters().Where(x=>x.TenantId==tenant&&x.EventId==eventId&&x.UserId==actor).MaxAsync(x=>(long?)x.EvidenceSequence,ct)??0)+1;_db.Add(AckEvidence(ack,"withdrawn",seq,kh,Hash("withdraw:"+id),actor));await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);return new(await Project(tenant,c.Event!,c.Actor!,c.Manage,ct));}

    public async Task<EventSafetyResult> RequestGuardianAsync(int tenant,int eventId,int actor,string? name,string? email,string? relationship,string? locale,string key,CancellationToken ct){name=Clean(name,150);email=email?.Trim().ToLowerInvariant();locale=Clean(locale,10)??"en";if(!ValidKey(key)||name is null||email is null||!System.Net.Mail.MailAddress.TryCreate(email,out _)||!Relationships.Contains(relationship??""))return Validation("guardian");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,false,ct);if(!c.Ok)return c.Error!;var p=await Published(tenant,eventId,ct);if(p is null||!p.Value.Version.GuardianConsentRequired)return Conflict();var kh=Hash(key);var replay=await _db.EventGuardianConsents.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.RequestIdempotencyHash==kh,ct);string? token=null;EventGuardianConsent consent;if(replay is not null){if(replay.EventId!=eventId||replay.MinorUserId!=actor)return Conflict();consent=replay;}else{var active=await _db.EventGuardianConsents.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.MinorUserId==actor&&(x.Status=="pending"||x.Status=="active"),ct);if(active)return Conflict();token="nxgc_"+B64(RandomNumberGenerator.GetBytes(32));consent=new(){TenantId=tenant,EventId=eventId,RequirementsId=p.Value.Head.Id,RequirementsVersionId=p.Value.Version.Id,RequirementsVersionNumber=p.Value.Version.VersionNumber,MinorUserId=actor,GuardianEmailCiphertext=_protector.Protect(email),GuardianIdentityCiphertext=_protector.Protect(name),GuardianEmailBlindHash=Hash(email),GuardianLocale=locale,RelationshipCode=relationship!,ConsentTextHash=Hash("guardian-consent-v1"),PolicyBindingHash=p.Value.Version.EligibilityPolicyHash,TokenHash=Hash(token),RequestedByUserId=actor,RequestIdempotencyHash=kh,RequestHash=Hash(new{name,email,relationship,locale}),ExpiresAt=DateTime.UtcNow.AddDays(1)};_db.Add(consent);await _db.SaveChangesAsync(ct);_db.Add(ConsentHistory(consent,"requested","platform_user",actor,kh,consent.RequestHash));await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);if(token is not null){var url=(_config["Frontend:BaseUrl"]??"http://localhost:5173").TrimEnd('/')+$"/events/{eventId}/guardian-consent?token={Uri.EscapeDataString(token)}";await _mail.SendEmailAsync(email,"Guardian consent request",$"<p>Hello {WebUtility.HtmlEncode(name)},</p><p><a href=\"{WebUtility.HtmlEncode(url)}\">Review guardian consent</a></p>",$"Review guardian consent: {url}",ct);}return new(await Project(tenant,c.Event!,c.Actor!,c.Manage,ct));}
    public async Task<EventSafetyResult> GrantGuardianAsync(string token,string email,string key,CancellationToken ct){if(!ValidKey(key)||!Regex.IsMatch(token??"","^nxgc_[A-Za-z0-9_-]{43}$")||!System.Net.Mail.MailAddress.TryCreate(email,out _))return GrantInvalid();var hash=Hash(token);await using var tx=await _db.Database.BeginTransactionAsync(ct);var consent=await _db.EventGuardianConsents.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TokenHash==hash,ct);if(consent is null||consent.ExpiresAt<=DateTime.UtcNow||consent.GuardianEmailBlindHash!=Hash(email.Trim().ToLowerInvariant()))return GrantInvalid();var kh=Hash(key);var replay=await _db.EventGuardianConsentHistory.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==consent.TenantId&&x.IdempotencyHash==kh,ct);if(!replay){if(consent.Status!="pending")return GrantInvalid();consent.Status="active";consent.ConsentVersion++;consent.TokenConsumedAt=DateTime.UtcNow;consent.GrantedAt=DateTime.UtcNow;consent.UpdatedAt=DateTime.UtcNow;_db.Add(ConsentHistory(consent,"granted","guardian_external",null,kh,Hash("grant:"+consent.Id)));await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);return new(new{status="granted"});}
    public async Task<EventSafetyResult> WithdrawGuardianAsync(int tenant,int eventId,int actor,long id,string key,CancellationToken ct){if(!ValidKey(key))return Validation("idempotency_key");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,false,ct);if(!c.Ok)return c.Error!;var consent=await _db.EventGuardianConsents.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==id&&x.MinorUserId==actor,ct);if(consent is null)return Missing();var kh=Hash(key);if(!await _db.EventGuardianConsentHistory.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.IdempotencyHash==kh,ct)){if(consent.Status is not("pending" or "active"))return Conflict();consent.Status="withdrawn";consent.ConsentVersion++;consent.WithdrawnByUserId=actor;consent.WithdrawnAt=DateTime.UtcNow;consent.UpdatedAt=DateTime.UtcNow;_db.Add(ConsentHistory(consent,"withdrawn","platform_user",actor,kh,Hash("withdraw:"+id)));await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);return new(await Project(tenant,c.Event!,c.Actor!,c.Manage,ct));}

    public async Task<EventSafetyResult> ReviewsAsync(int tenant,int eventId,int actor,int page,int perPage,CancellationToken ct){var c=await Context(tenant,eventId,actor,true,ct);if(!c.Ok)return c.Error!;return new(await ReviewsProjection(tenant,eventId,page,perPage,ct));}
    public async Task<EventSafetyResult> RecordReviewAsync(int tenant,int eventId,int actor,int userId,string decision,string reason,DateTime from,DateTime? until,long? expected,string key,CancellationToken ct){if(!ValidKey(key)||!Decisions.Contains(decision)||!Reasons.Contains(reason)||until<=from)return Validation("review");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,true,ct);if(!c.Ok)return c.Error!;if(!await _db.Users.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.Id==userId&&x.IsActive,ct))return Missing();var kh=Hash(key);var replay=await _db.EventParticipationDenialHistory.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.IdempotencyHash==kh,ct);if(!replay){var row=await _db.EventParticipationDenials.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.UserId==userId&&x.Status=="active",ct);if(row is null){if(expected is not null and not 0)return Conflict();row=new(){TenantId=tenant,EventId=eventId,UserId=userId,Decision=decision,ReasonCode=reason,ReviewedByUserId=actor,EffectiveFrom=from,EffectiveUntil=until,CreateIdempotencyHash=kh,CreateRequestHash=Hash(new{userId,decision,reason,from,until})};_db.Add(row);}else{if(expected!=row.DecisionVersion)return Conflict();row.Decision=decision;row.ReasonCode=reason;row.EffectiveFrom=from;row.EffectiveUntil=until;row.DecisionVersion++;row.ReviewedByUserId=actor;row.UpdatedAt=DateTime.UtcNow;}await _db.SaveChangesAsync(ct);_db.Add(DenialHistory(row,"recorded",actor,kh,Hash(new{userId,decision,reason,from,until})));await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);return new(await ReviewsProjection(tenant,eventId,1,25,ct));}
    public async Task<EventSafetyResult> WithdrawReviewAsync(int tenant,int eventId,int actor,long id,long expected,string key,CancellationToken ct){if(!ValidKey(key)||expected<1)return Validation("expected_version");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,true,ct);if(!c.Ok)return c.Error!;var row=await _db.EventParticipationDenials.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==id,ct);if(row is null)return Missing();var kh=Hash(key);if(!await _db.EventParticipationDenialHistory.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.IdempotencyHash==kh,ct)){if(row.Status!="active"||row.DecisionVersion!=expected)return Conflict();row.Status="withdrawn";row.DecisionVersion++;row.WithdrawnByUserId=actor;row.WithdrawnAt=DateTime.UtcNow;row.UpdatedAt=DateTime.UtcNow;_db.Add(DenialHistory(row,"withdrawn",actor,kh,Hash("withdraw:"+id)));await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);return new(await ReviewsProjection(tenant,eventId,1,25,ct));}

    private async Task<object> Project(int tenant,Event e,User actor,bool manage,CancellationToken ct){var head=await _db.EventSafetyRequirements.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==e.Id,ct);EventSafetyRequirementVersion? version=null;if(head is not null)version=await _db.EventSafetyRequirementVersions.IgnoreQueryFilters().AsNoTracking().SingleAsync(x=>x.TenantId==tenant&&x.RequirementsId==head.Id&&x.VersionNumber==(head.PublishedVersion??head.CurrentVersion),ct);var ack=await CurrentAck(tenant,e.Id,actor.Id,ct);var consent=await _db.EventGuardianConsents.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==e.Id&&x.MinorUserId==actor.Id).OrderByDescending(x=>x.Id).FirstOrDefaultAsync(ct);var denial=await _db.EventParticipationDenials.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==e.Id&&x.UserId==actor.Id&&x.Status=="active"&&(x.EffectiveUntil==null||x.EffectiveUntil>DateTime.UtcNow),ct);var requirements=head is null||version is null?null:new{status=head.Status,revision=head.Revision,current_version=head.CurrentVersion,published_version=head.PublishedVersion,version=Version(version,head.PublishedAt)};var cocRequired=head?.Status=="published"&&version?.CodeOfConductRequired==true;var guardianRequired=head?.Status=="published"&&version?.GuardianConsentRequired==true;var reasons=new List<string>();var actions=new List<string>();if(head?.Status!="published")reasons.Add("event_safety_requirements_not_published");if(cocRequired&&ack is null){reasons.Add("event_safety_code_of_conduct_acknowledgement_required");actions.Add("event_safety_acknowledge_code_of_conduct");}if(guardianRequired&&consent?.Status!="active"){reasons.Add("event_safety_guardian_consent_required");actions.Add("event_safety_request_guardian_consent");}if(denial is not null)reasons.Add("event_safety_active_participation_denial");var status=head?.Status!="published"?"not_evaluated":reasons.Count==0?"allow":"deny";return new{contract_version=1,event_id=e.Id,rollout=new{mode="enforce",source="global",configuration_valid=true,enforcement_active=true},requirements,eligibility=new{status,reason_codes=reasons,required_actions=actions,requirements_version=head?.PublishedVersion,age_at_event=(int?)null,minor_at_event=(bool?)null},evidence=new{code_of_conduct=new{status=!cocRequired?"not_required":ack is null?"required":"acknowledged",acknowledgement_id=ack?.Id,text_version=version?.CodeOfConductTextVersion,acknowledged_at=IsoN(ack?.AcknowledgedAt)},guardian_consent=new{status=!guardianRequired?"not_required":consent?.Status??"required",consent_id=consent?.Id,consent_version=consent?.ConsentVersion,expires_at=IsoN(consent?.ExpiresAt),granted_at=IsoN(consent?.GrantedAt)},active_denial=denial is null?null:new{id=denial.Id,decision=denial.Decision,reason_code=denial.ReasonCode,status=denial.Status,decision_version=denial.DecisionVersion,effective_from=Iso(denial.EffectiveFrom),effective_until=IsoN(denial.EffectiveUntil)}},permissions=new{manage_requirements=manage,review_participation=manage,acknowledge_code_of_conduct=!manage&&cocRequired&&ack is null,withdraw_code_of_conduct=!manage&&ack is not null,request_guardian_consent=!manage&&guardianRequired&&consent?.Status is not("pending" or "active"),withdraw_guardian_consent=!manage&&consent?.Status is "pending" or "active"},privacy=new{guardian_identity_redacted=true,guardian_token_redacted=true,safeguarding_policy_evidence_redacted=true,free_text_review_notes_supported=false}};}
    private async Task<object> ReviewsProjection(int tenant,int eventId,int page,int perPage,CancellationToken ct){page=Math.Max(1,page);perPage=Math.Clamp(perPage,1,100);var q=_db.EventParticipationDenials.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId);var total=await q.CountAsync(ct);var rows=await q.OrderByDescending(x=>x.CreatedAt).Skip((page-1)*perPage).Take(perPage).ToListAsync(ct);var ids=rows.Select(x=>x.Id).ToArray();var histories=await _db.EventParticipationDenialHistory.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&ids.Contains(x.DenialId)).OrderBy(x=>x.DecisionVersion).ToListAsync(ct);var userIds=rows.SelectMany(x=>new[]{x.UserId,x.ReviewedByUserId}).Concat(histories.Select(x=>x.ReviewerUserId)).Distinct().ToArray();var users=await _db.Users.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&userIds.Contains(x.Id)).ToDictionaryAsync(x=>x.Id,ct);return new{items=rows.Select(x=>new{denial=new{id=x.Id,decision=x.Decision,reason_code=x.ReasonCode,status=x.Status,decision_version=x.DecisionVersion,effective_from=Iso(x.EffectiveFrom),effective_until=IsoN(x.EffectiveUntil),reviewed_at=Iso(x.CreatedAt)},member=new{id=x.UserId,display_name=users.TryGetValue(x.UserId,out var u)?Name(u):"",avatar_url=users.TryGetValue(x.UserId,out u)?u.AvatarUrl:null},reviewer=Actor(users,x.ReviewedByUserId),history=histories.Where(h=>h.DenialId==x.Id).Select(h=>new{decision_version=h.DecisionVersion,decision=h.Decision,reason_code=h.ReasonCode,status=h.Status,action=h.Action,effective_from=Iso(h.EffectiveFrom),effective_until=IsoN(h.EffectiveUntil),reviewed_at=Iso(h.CreatedAt),reviewer=Actor(users,h.ReviewerUserId)})}),total,page,per_page=perPage};}
    private async Task<(bool Ok,Event? Event,User? Actor,bool Manage,EventSafetyResult? Error)> Context(int tenant,int eventId,int actor,bool requireManage,CancellationToken ct){var e=await _db.Events.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.Id==eventId,ct);if(e is null)return(false,null,null,false,Missing());var u=await _db.Users.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.Id==actor&&x.IsActive,ct);if(u is null)return(false,e,null,false,Forbidden());var manage=IsAdmin(u)||e.CreatedById==actor||await _db.EventStaffAssignments.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.UserId==actor&&x.Status=="active"&&(x.Role=="event_manager"||x.Role=="co_organizer"),ct);if(requireManage&&!manage)return(false,e,u,false,Forbidden());return(true,e,u,manage,null);}
    private async Task<(EventSafetyRequirement Head,EventSafetyRequirementVersion Version)?> Published(int t,int e,CancellationToken ct){var h=await _db.EventSafetyRequirements.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==t&&x.EventId==e&&x.Status=="published",ct);if(h?.PublishedVersion is not int v)return null;return(h,await _db.EventSafetyRequirementVersions.IgnoreQueryFilters().SingleAsync(x=>x.TenantId==t&&x.RequirementsId==h.Id&&x.VersionNumber==v,ct));}
    private async Task<EventSafetyCodeAcknowledgement?> CurrentAck(int t,int e,int u,CancellationToken ct){var all=await _db.EventSafetyCodeAcknowledgements.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==t&&x.EventId==e&&x.UserId==u).OrderBy(x=>x.EvidenceSequence).ToListAsync(ct);EventSafetyCodeAcknowledgement? current=null;foreach(var x in all){if(x.Action=="acknowledged")current=x;else if(x.ReferencedAcknowledgementId==current?.Id)current=null;}return current;}
