"EVENT_SAFETY_FORBIDDEN","Forbidden",403));private static EventSafetyResult Conflict()=>new(null,new("EVENT_SAFETY_CONFLICT","Version or state conflict",409));private static EventSafetyResult Validation(string f)=>new(null,new("EVENT_SAFETY_VALIDATION_FAILED","Validation failed",422,f));private static EventSafetyResult GrantInvalid()=>new(null,new("EVENT_GUARDIAN_CONSENT_INVALID","Invalid input",422));
